cdp_helper.example_submit_prompt:
const ws = new WebSocket('ws://127.0.0.1:9333/devtools/page/{PAGE_ID}');
ws.on('open', () => {
  // Type
  ws.send(JSON.stringify({id:1, method:'Runtime.evaluate', params:{expression: "document.querySelector('.ProseMirror').focus(); document.execCommand('insertText', false, 'YOUR PROMPT HERE')"}}));
  // Submit after 500ms
  setTimeout(() => {
    ws.send(JSON.stringify({id:2, method:'Input.dispatchKeyEvent', params:{type:'keyDown', key:'Enter', code:'Enter', modifiers:4, windowsVirtualKeyCode:13}}));
    setTimeout(() => {
      ws.send(JSON.stringify({id:3, method:'Input.dispatchKeyEvent', params:{type:'keyUp', key:'Enter', code:'Enter', modifiers:4, windowsVirtualKeyCode:13}}));
    }, 100);
  }, 500);
});
